  ('public-health-specialist-moex-00677', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列關於社會規範（socialnorm）的敘述，何者錯誤？', '["大部分的人會高估不良行為（undesirablebehaviors）的盛行率（prevalence）", "描述性規範（descriptivenorm）討論的是別人怎麼做；指令式規範（injunctivenorm）討論 的是別人期待你怎麼做", "社會認知理論認為社會規範透過社會結果（social consequences）和自我評價結果（self- evaluativeconsequences）去影響行為", "同一個人對於不同的參考對象（referent）會有相同的程度去遵守（comply）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00678', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某人打算最近一個月內要開始規律運動，已購買運動服裝，且上網查詢住家附近的運動中心 及相關運動課程，此敘述屬於跨理論模式（TranstheoreticalModel,TTM）中的何種改變階段？', '["沉思期（contemplation）", "準備期（preparation）", "行動期（action）", "維持期（maintenance）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00679', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '在跨理論模式（TranstheoreticalModel,TTM）裡，「改變階段（stageofchange）」用別種較為 健康的選項替代不健康的行為，屬於何種「改變階段」？', '["反制約（counter-conditioning）", "自我解放（self-liberation）", "刺激控制（stimuluscontrol）", "社會解放（socialliberation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00680', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '評估介入的研究設計方法中，下列敘述何者錯誤？', '["隨機對照試驗（randomizedcontrolledtrial）屬於一種實驗設計（experimentaldesign）", "比起非實驗設計，實驗設計更能控制掉可能的干擾因子（confounders）", "準實驗設計（quasi-experimental designs）被用在無法將研究參與者隨機分派成實驗組和控 制組的時候", "準實驗設計（quasi-experimentaldesigns）是廣泛被用在臨床試驗上的黃金標準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00681', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關健康促進計畫的評價（evaluation）之敘述，何者錯誤？', '["辦完一場工作坊，調查學員對活動的滿意度與感受到的幫助程度，是一種結果評價（outcome evaluation）", "子宮頸癌篩檢可降低子宮頸癌死亡率，政府責成所屬機構配合辦理篩檢場次逐年增加，為 一種過程評價（processevaluation）指標", "某機構辦理菸害防治宣導活動，了解參與者之菸害知識是否有所提升，是一種結果評價 （outcomeevaluation）", "監控計畫是否按照預定的規劃推動，是一種過程評價（processevaluation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00682', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '在評估介入時，過程評估（processevaluation）裡評估「研究對象被暴露到多少程度的介入」 為下列何者？', '["脈絡（context）", "劑量交付（dosedelivered）", "劑量接收（dosereceived）", "招募（recruitment）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00683', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關社區健康促進計畫的需求評估（needsassessment），下列何者錯誤？', '["需求評估一開始就須將居民納入進來，以強化居民對計畫的擁有感（ownership）", "除了了解健康問題及其影響因子，也要了解社區所擁有的資產（asset）為何", "拜訪社區的關鍵人物或作決定者，讓他們了解計畫，爭取他們的支持與合作", "社區中的弱勢族群，例如低收入戶、患病者，是計畫要照顧的對象，不需要了解他們擁有 的資產（asset）為何，以免他們過度負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00684', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '於介入方案之規劃階段可進行教育和生態評估（educationalandecologicalassessment），若參 與調查訪談之吸菸者表示，因受到同住家人之抱怨，故決定報名參加戒菸班，此敘述屬下列 何種因素？', '["前傾因素（predisposingfactor）", "增強因素（reinforcingfactor）", "使能因素（enablingfactor）", "調節因素（moderatingfactor）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00685', 'public-health-specialist', 'public-health-specialist-moex-111-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '在推動社區組織（communityorganizing）計畫時，有三種常用的模式，下列何者錯誤？', '["地區發展（localitydevelopment）", "社會參與（socialparticipation）", "社會計畫（socialplanning）", "社會行動（socialaction）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:39+00:00", "source_pdf_sha1": "86070c582125", "answer_pdf_sha1": "c17ed1f53ce8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
